//! # E_8 lattice quantization of token-embedding vectors.
//!
//! The embedding matrix consumed by [`crate::columnar_embed_backend`] is
//! `vocab_size × hidden_dim` (e.g. Qwen2.5-0.5B: 151,936 × 896). Each ROW is
//! one token's learned latent vector — high-dimensional, learned to be
//! near-isotropic and decorrelated across dims (the whole point of a learned
//! embedding is to spread tokens across the latent space). That is the
//! textbook **cell-filling** regime for the certified E_8 quantizer
//! ([`crate::e8_quantizer`]), and `hidden_dim` is almost always a multiple of
//! 8 (896 = 112·8), so the full ~14% E_8 edge is available with NO tail.
//!
//! ## The PROVEN recipe (mirrors `n_rgb_lattice_quant`, +9.30% measured)
//!
//!   1. **CENTER** each row: subtract its per-vector DC mean, add it back.
//!      Many embedding matrices carry a strong DC component (a learned
//!      "mean token" direction); quantizing raw wastes the lattice on it.
//!   2. **`floor(d/8)` full E_8 cells + cubic tail** on the `d % 8` leftover.
//!      NEVER zero-pad the final block up to 8 (dead dims collapse effective
//!      dimension — the wash the recipe warns about).
//!   3. **MEASURE cell-filling FIRST** ([`characterize_embed_cell_filling`])
//!      and only claim a win if the rows fill cells; expected blended edge is
//!      `(8·blocks / d) × 14%`.
//!
//! Additive + default-off: [`EmbedQuantizer::None`] is byte-for-byte
//! pass-through. API mirrors `kv_cache_e8` / `n_rgb_lattice_quant`.

#![allow(dead_code)]

use crate::e8_quantizer::nearest_e8;

/// Which lattice scheme to apply to an embedding row. Additive + opt-in.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum EmbedQuantizer {
    /// No quantization — pass-through. (Default.)
    #[default]
    None,
    /// Cubic ℤ^d quantization at `step`. Worst-case lattice (G = 1/12).
    Cubic,
    /// `floor(d/8)` full E_8 cells + cubic tail on the `d % 8` leftover.
    /// RECOMMENDED: every cell-filling 8-block takes the ~14% E_8 edge; no
    /// zero-padding (dead dims).
    E8Tail,
    /// `ceil(d/8)` E_8 cells, final block zero-padded. ONLY to measure the
    /// dead-dim wash; never the recommendation when `d % 8 != 0`.
    E8Pad,
}

/// Centring mode applied before quantization.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum EmbedCentering {
    /// Quantize raw (origin-displaced). NOT recommended.
    Raw,
    /// Subtract per-row mean, add it back after. Cell-filling enabler.
    #[default]
    PerVectorMean,
}

/// Config for the embedding E_8 path. Mirrors `KvQuantConfig`.
#[derive(Clone, Copy, Debug)]
pub struct EmbedQuantConfig {
    pub quantizer: EmbedQuantizer,
    pub centering: EmbedCentering,
    /// Cell-edge step in feature units; cubic and E_8 share it (equal bits).
    pub step: f32,
}

impl Default for EmbedQuantConfig {
    fn default() -> Self {
        Self {
            quantizer: EmbedQuantizer::None,
            centering: EmbedCentering::PerVectorMean,
            step: 0.01,
        }
    }
}

#[inline]
fn quantize_e8_block(block: &[f64; 8], step: f32) -> [f32; 8] {
    let mut scaled = [0.0_f64; 8];
    for k in 0..8 {
        scaled[k] = block[k] * (2.0 / step as f64);
    }
    let qc = nearest_e8(scaled);
    let mut out = [0.0_f32; 8];
    for k in 0..8 {
        out[k] = ((qc[k] as f64) * (step as f64 / 2.0)) as f32;
    }
    out
}

/// Quantize one embedding row of dimension `d = v.len()` into `out` (same
/// length). [`EmbedQuantizer::None`] copies verbatim. Returns mean-absolute
/// quantization noise over the `d` coords (against the centred input).
pub fn quantize_embed_into(v: &[f32], out: &mut [f32], cfg: &EmbedQuantConfig) -> f32 {
    debug_assert_eq!(v.len(), out.len(), "quantize_embed_into: length mismatch");
    let d = v.len();
    if cfg.quantizer == EmbedQuantizer::None || d == 0 {
        out.copy_from_slice(v);
        return 0.0;
    }
    let step = cfg.step.max(1e-7);

    let mean = match cfg.centering {
        EmbedCentering::Raw => 0.0_f32,
        EmbedCentering::PerVectorMean => v.iter().copied().sum::<f32>() / d as f32,
    };
    let mut c = vec![0.0_f32; d];
    for i in 0..d {
        c[i] = v[i] - mean;
    }

    let mut q = vec![0.0_f32; d];
    match cfg.quantizer {
        EmbedQuantizer::None => unreachable!(),
        EmbedQuantizer::Cubic => {
            let inv = 1.0_f32 / step;
            for i in 0..d {
                q[i] = (c[i] * inv).round() * step;
            }
        }
        EmbedQuantizer::E8Tail => {
            let blocks = d / 8;
            for b in 0..blocks {
                let base = b * 8;
                let mut block = [0.0_f64; 8];
                for k in 0..8 {
                    block[k] = c[base + k] as f64;
                }
                let qb = quantize_e8_block(&block, step);
                for k in 0..8 {
                    q[base + k] = qb[k];
                }
            }
            let inv = 1.0_f32 / step;
            for i in (blocks * 8)..d {
                q[i] = (c[i] * inv).round() * step;
            }
        }
        EmbedQuantizer::E8Pad => {
            let mut i = 0usize;
            while i < d {
                let mut block = [0.0_f64; 8];
                for k in 0..8 {
                    block[k] = if i + k < d { c[i + k] as f64 } else { 0.0 };
                }
                let qb = quantize_e8_block(&block, step);
                for k in 0..8 {
                    if i + k < d {
                        q[i + k] = qb[k];
                    }
                }
                i += 8;
            }
        }
    }

    let mut noise = 0.0_f32;
    for i in 0..d {
        noise += (c[i] - q[i]).abs();
        out[i] = q[i] + mean;
    }
    noise / d as f32
}

/// Allocating convenience wrapper around [`quantize_embed_into`].
pub fn quantize_embed_vec(v: &[f32], cfg: &EmbedQuantConfig) -> Vec<f32> {
    let mut out = vec![0.0_f32; v.len()];
    quantize_embed_into(v, &mut out, cfg);
    out
}

// ── Cell-filling diagnostics ───────────────────────────────────────────────

/// Cell-filling diagnostics for a set of `d`-dim embedding rows at `step`.
#[derive(Clone, Debug)]
pub struct EmbedCellFillingReport {
    pub n: usize,
    pub dim: usize,
    pub min: f32,
    pub max: f32,
    pub centered_std: f32,
    pub mean_abs_corr: f32,
    pub max_abs_corr: f32,
    pub effective_dim: f32,
    pub spread_in_cells: f32,
    pub cells_occupied: usize,
    pub is_cell_filling: bool,
}

/// Characterize embedding rows at `step` on the **per-row DC-removed
/// residual** — exactly what the recipe's `PerVectorMean` E8Tail quantizer
/// sees. A strong shared "mean token" DC direction would otherwise look like a
/// rank-1 all-dims correlation and collapse the effective dimension; removing
/// it per row measures the true AC structure. Frobenius identity for the
/// effective dim — no eigensolver. The d×d covariance is O(d²) memory; callers
/// pass a representative subset of rows (a few thousand) for the shape.
pub fn characterize_embed_cell_filling(data: &[Vec<f32>], step: f32) -> EmbedCellFillingReport {
    let n = data.len();
    assert!(n > 0, "need rows to characterize");
    let d = data[0].len();
    assert!(d > 0, "rows must be non-empty");
    for v in data {
        assert_eq!(v.len(), d, "all rows must share dimension");
    }
    let nf = n as f64;

    // Per-row DC-removed residual rows (the AC structure the lattice sees).
    let mut min = f32::INFINITY;
    let mut max = f32::NEG_INFINITY;
    let mut ac: Vec<Vec<f64>> = Vec::with_capacity(n);
    for v in data {
        let m = v.iter().copied().sum::<f32>() as f64 / d as f64;
        let mut r = vec![0.0_f64; d];
        for j in 0..d {
            min = min.min(v[j]);
            max = max.max(v[j]);
            r[j] = v[j] as f64 - m;
        }
        ac.push(r);
    }

    let mut mean = vec![0.0_f64; d];
    for r in &ac {
        for j in 0..d {
            mean[j] += r[j];
        }
    }
    for j in 0..d {
        mean[j] /= nf;
    }

    let mut cov = vec![0.0_f64; d * d];
    let mut centered_sq = 0.0_f64;
    let mut cbuf = vec![0.0_f64; d];
    for r in &ac {
        for j in 0..d {
            cbuf[j] = r[j] - mean[j];
            centered_sq += cbuf[j] * cbuf[j];
        }
        for i in 0..d {
            let ci = cbuf[i];
            let row = i * d;
            for j in 0..d {
                cov[row + j] += ci * cbuf[j];
            }
        }
    }
    for x in cov.iter_mut() {
        *x /= nf;
    }
    let centered_std = (centered_sq / (nf * d as f64)).sqrt() as f32;

    let mut sum_abs = 0.0_f64;
    let mut max_abs = 0.0_f64;
    let mut cnt = 0usize;
    for i in 0..d {
        for j in 0..d {
            if i == j {
                continue;
            }
            let denom = (cov[i * d + i] * cov[j * d + j]).sqrt();
            let r = if denom > 0.0 {
                cov[i * d + j] / denom
            } else {
                0.0
            };
            sum_abs += r.abs();
            max_abs = max_abs.max(r.abs());
            cnt += 1;
        }
    }
    let mean_abs_corr = (sum_abs / cnt.max(1) as f64) as f32;
    let max_abs_corr = max_abs as f32;

    let mut trace = 0.0_f64;
    let mut fro2 = 0.0_f64;
    for i in 0..d {
        trace += cov[i * d + i];
    }
    for x in &cov {
        fro2 += x * x;
    }
    let effective_dim = if fro2 > 0.0 {
        (trace * trace / fro2) as f32
    } else {
        0.0
    };

    let step = step.max(1e-7);
    let inv = 1.0_f32 / step;
    let mut seen = std::collections::HashSet::new();
    for v in data {
        let m = v.iter().copied().sum::<f32>() / d as f32;
        let key: Vec<i64> = v.iter().map(|&x| ((x - m) * inv).round() as i64).collect();
        seen.insert(key);
    }
    let cells_occupied = seen.len();
    let spread_in_cells = centered_std / step;
    let is_cell_filling = spread_in_cells >= 1.0 && effective_dim >= 8.0 && mean_abs_corr <= 0.2;

    EmbedCellFillingReport {
        n,
        dim: d,
        min,
        max,
        centered_std,
        mean_abs_corr,
        max_abs_corr,
        effective_dim,
        spread_in_cells,
        cells_occupied,
        is_cell_filling,
    }
}

/// Mean per-coordinate squared quantization error of `quantizer` over a row
/// set at `step`. Head-to-head metric (lower = less noise, equal bits).
pub fn mean_sq_quant_error(
    data: &[Vec<f32>],
    quantizer: EmbedQuantizer,
    centering: EmbedCentering,
    step: f32,
) -> f64 {
    if data.is_empty() {
        return 0.0;
    }
    let cfg = EmbedQuantConfig {
        quantizer,
        centering,
        step,
    };
    let d = data[0].len();
    let mut out = vec![0.0_f32; d];
    let mut acc = 0.0_f64;
    let mut count = 0usize;
    for v in data {
        quantize_embed_into(v, &mut out, &cfg);
        for j in 0..v.len() {
            let e = (v[j] - out[j]) as f64;
            acc += e * e;
        }
        count += v.len();
    }
    acc / count.max(1) as f64
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::e8_quantizer::SplitMix64;

    /// Deterministic synthetic embedding rows that mimic a learned embedding
    /// matrix: near-isotropic, decorrelated across dims, with a shared DC
    /// "mean token" direction (a single offset added to every row's coords)
    /// that centring removes. `hidden_dim` matches the tree's models
    /// (896 = 112·8 for Qwen2.5-0.5B). Small per-dim std (~0.02) like a real
    /// embedding after the typical 1/sqrt(d) init has trained.
    fn synthetic_embed(n: usize, hidden: usize, seed: u64, sigma: f32, dc: f32) -> Vec<Vec<f32>> {
        let mut rng = SplitMix64::new(seed);
        let mut out = Vec::with_capacity(n);
        for _ in 0..n {
            let row_dc = dc + rng.next_in(0.1) as f32; // per-row DC drift
            let mut v = vec![0.0_f32; hidden];
            for j in 0..hidden {
                let g = (rng.next_in(1.0) + rng.next_in(1.0) + rng.next_in(1.0) + rng.next_in(1.0))
                    as f32
                    / 2.0;
                v[j] = row_dc + sigma * g;
            }
            out.push(v);
        }
        out
    }

    #[test]
    fn pass_through_when_off_is_byte_for_byte() {
        let v: Vec<f32> = (0..896).map(|i| (i as f32 * 0.001).sin() * 0.02).collect();
        let cfg = EmbedQuantConfig::default();
        assert_eq!(cfg.quantizer, EmbedQuantizer::None);
        let out = quantize_embed_vec(&v, &cfg);
        assert_eq!(out, v, "None must pass through byte-for-byte");
    }

    #[test]
    fn quantizers_produce_finite_output() {
        let v: Vec<f32> = (0..900)
            .map(|i| 0.005 + 0.02 * (i as f32 * 0.07).cos())
            .collect();
        for q in [
            EmbedQuantizer::Cubic,
            EmbedQuantizer::E8Tail,
            EmbedQuantizer::E8Pad,
        ] {
            let cfg = EmbedQuantConfig {
                quantizer: q,
                ..Default::default()
            };
            let out = quantize_embed_vec(&v, &cfg);
            assert_eq!(out.len(), v.len());
            assert!(out.iter().all(|x| x.is_finite()), "{q:?} finite");
        }
    }

    /// CHARACTERIZATION — lead with this. hidden_dim 896 (Qwen2.5-0.5B) and
    /// 768 (common). Both multiples of 8 ⇒ full E_8, no tail.
    #[test]
    fn characterize_embed_cell_filling_print() {
        for &d in &[768usize, 896] {
            let data = synthetic_embed(3000, d, 0xE3BE_0000 ^ d as u64, 0.02, 0.05);
            let step = 0.01_f32;
            let r = characterize_embed_cell_filling(&data, step);
            println!(
                "\n[embed characterization] hidden_dim={d} N={}\n  \
                 range=[{:.4},{:.4}] centered_std={:.5}\n  \
                 mean|corr|={:.4} max|corr|={:.4} effective_dim={:.2}/{}\n  \
                 step={step} spread_in_cells={:.2} cells_occupied={}/{} ({:.1}%)\n  \
                 => CELL-FILLING: {}",
                r.n,
                r.min,
                r.max,
                r.centered_std,
                r.mean_abs_corr,
                r.max_abs_corr,
                r.effective_dim,
                d,
                r.spread_in_cells,
                r.cells_occupied,
                r.n,
                100.0 * r.cells_occupied as f32 / r.n as f32,
                if r.is_cell_filling { "YES" } else { "NO" },
            );
            assert_eq!(r.dim, d);
            assert!(r.centered_std > 0.0);
            assert!(r.effective_dim > 0.0 && r.effective_dim <= d as f32 + 1e-2);
        }
    }

    /// PROPERTY: E_8 beats cubic at equal bits on the cell-filling centred
    /// embedding rows — asserted only when the characterization says so.
    #[test]
    fn e8_vs_cubic_on_embed_tied_to_cell_filling() {
        let d = 896usize; // 112 full E_8 cells, no tail.
        let data = synthetic_embed(4000, d, 0xEB80_0FED, 0.02, 0.05);
        let step = 0.01_f32;
        let report = characterize_embed_cell_filling(&data, step);

        let mse_cubic = mean_sq_quant_error(
            &data,
            EmbedQuantizer::Cubic,
            EmbedCentering::PerVectorMean,
            step,
        );
        let mse_e8 = mean_sq_quant_error(
            &data,
            EmbedQuantizer::E8Tail,
            EmbedCentering::PerVectorMean,
            step,
        );
        let mse_e8_raw =
            mean_sq_quant_error(&data, EmbedQuantizer::E8Tail, EmbedCentering::Raw, step);
        let pct = (1.0 - mse_e8 / mse_cubic) * 100.0;
        let pct_raw = (1.0 - mse_e8_raw / mse_cubic) * 100.0;
        println!(
            "\n[embed E8 vs cubic | hidden_dim={d}] step={step} cell_filling={}\n  \
             MSE cubic ℤ^{d}        = {mse_cubic:.8}\n  \
             MSE E8Tail (centred)  = {mse_e8:.8}  ({pct:+.2}% vs cubic)  <- recommended\n  \
             MSE E8Tail (RAW/noDC) = {mse_e8_raw:.8}  ({pct_raw:+.2}% vs cubic)\n  \
             prediction: d%8==0 ⇒ full E_8 ⇒ ~14% MSE reduction",
            report.is_cell_filling,
        );

        if report.is_cell_filling {
            assert!(
                mse_e8 < mse_cubic,
                "cell-filling ⇒ E8Tail must beat cubic: e8={mse_e8:.8} cubic={mse_cubic:.8}"
            );
            assert!(
                pct > 8.0 && pct < 20.0,
                "expected ~14% (all dims E_8), got {pct:.2}%"
            );
        } else {
            println!("  (NOT cell-filling at this step → E_8 edge not expected)");
        }
    }

    /// END-TO-END, COLD vs WARM at hidden_dim 896.
    #[test]
    fn bench_embed_baseline_vs_cubic_vs_e8_cold_warm() {
        let d = 896usize;
        let data = synthetic_embed(5000, d, 0xD00D_0896, 0.02, 0.05);
        let step = 0.01_f32;
        let recon = |q: EmbedQuantizer| -> (f64, std::time::Duration) {
            let cfg = EmbedQuantConfig {
                quantizer: q,
                centering: EmbedCentering::PerVectorMean,
                step,
            };
            let mut out = vec![0.0_f32; d];
            let t = std::time::Instant::now();
            let mut acc = 0.0_f64;
            for v in &data {
                quantize_embed_into(v, &mut out, &cfg);
                for j in 0..d {
                    let e = (v[j] - out[j]) as f64;
                    acc += e * e;
                }
            }
            ((acc / (data.len() * d) as f64).sqrt(), t.elapsed())
        };
        let (base_c, tb_c) = recon(EmbedQuantizer::None);
        let (cub_c, tc_c) = recon(EmbedQuantizer::Cubic);
        let (e8_c, te_c) = recon(EmbedQuantizer::E8Tail);
        let (base_w, tb_w) = recon(EmbedQuantizer::None);
        let (cub_w, tc_w) = recon(EmbedQuantizer::Cubic);
        let (e8_w, te_w) = recon(EmbedQuantizer::E8Tail);
        let ratio = e8_w / cub_w.max(1e-12);
        let pct = (1.0 - ratio * ratio) * 100.0;
        println!(
            "\n[embed end-to-end hidden_dim={d}] N={} step={step}\n  \
             BASELINE(none) RMSE={base_c:.8} (warm {base_w:.8}) | COLD {tb_c:?} WARM {tb_w:?}\n  \
             CUBIC ℤ^{d}     RMSE={cub_c:.8} (warm {cub_w:.8}) | COLD {tc_c:?} WARM {tc_w:?}\n  \
             E8Tail         RMSE={e8_c:.8} (warm {e8_w:.8}) | COLD {te_c:?} WARM {te_w:?}\n  \
             VERDICT (warm): E8/cubic RMSE ratio={ratio:.4} => MSE {pct:+.2}% vs cubic",
            data.len(),
        );
        assert_eq!(base_c, 0.0, "baseline pass-through is exact");
        assert!(ratio <= 1.001, "E8Tail must be ≤ cubic: ratio={ratio:.4}");
    }
}
